# parse one order path to product order quantities
for day in [1,2,3]:
    print('DAY',day)
    # total supplier qty by product
    sup={}
    for path in glob.glob(f'/app/raw_supplier_receipts/day_{day:03d}_*'):
        txt=Path(path).read_text().strip()
        items=[]
        if path.endswith('.json'):
            data=json.loads(txt); items=[(i['prod_id'],i['delivered_qty']) for i in data['items']]
        elif path.endswith('.csv'):
            df=pd.read_csv(path,sep=';'); items=list(df[['PRODUCT','DELIVERED_QTY']].itertuples(index=False,name=None))
        elif 'key-value' in path:
            for line in txt.splitlines():
                m=re.search(r'PRODUCT: (P_\d+) \| DELIVERED_QTY: (\d+)',line)
                if m: items.append((m.group(1), int(m.group(2))))
        else:
            for line in txt.splitlines():
                m=re.search(r'product (P_\d+) delivered (\d+) units',line)
                if m: items.append((m.group(1), int(m.group(2))))
        for p,q in items: sup[p]=sup.get(p,0)+q
    # store sequence
    stores=[]
    for path in glob.glob(f'/app/raw_wholesaler_store_receipts/day_{day:03d}_*_receipt.txt'):
        txt=Path(path).read_text()
        s=re.search(r'STORE_ID: (S_\d+)',txt).group(1)
        seq=int(re.search(r'DAILY_SEQUENCE_NO: (\d+)',txt).group(1))
        tot=int(re.search(r'TOTAL_DELIVERED_UNITS: (\d+)',txt).group(1))
        stores.append((seq,s,tot))
    stores.sort()
    inv=sup.copy()
    ok=True
    for seq,s,tot in stores:
        path=glob.glob(f'/app/raw_orders/day_{day:03d}_{s}_*')[0]
        txt=Path(path).read_text().strip()
        items=[]
        if path.endswith('.json'):
            data=json.loads(txt); items=[(i['prod_id'],i['qty']) for i in data['items']]
        elif path.endswith('.csv'):
            df=pd.read_csv(path,sep=';'); items=list(df[['PRODUCT','QUANTITY']].itertuples(index=False,name=None))
        elif 'key-value' in path:
            for line in txt.splitlines():
                m=re.search(r'ORDER_PRODUCT: (P_\d+) \| ORDER_QTY: (\d+)',line)
                if m: items.append((m.group(1), int(m.group(2))))
        else:
            for line in txt.splitlines():
                m=re.search(r'product (P_\d+).*deliver (\d+) units',line)
                if m: items.append((m.group(1), int(m.group(2))))
        rem=tot
        alloc=[]
        for p,q in items:
            if rem<=0: break
            take=min(q, rem, inv.get(p,0))
            alloc.append((p,take))
            inv[p]=inv.get(p,0)-take
            rem-=take
            if take<q:
                # if rem still >0 but inv shortage hit, algorithm breaks? under brutal first-come maybe move to next product? unclear.
                if rem>0:
                    alloc.append(('SHORT_ON_'+p, rem))
                break
        if rem!=0:
            ok=False
            print(' store',s,'seq',seq,'could not allocate prefix exactly, rem',rem,'tot',tot,'last alloc',alloc[-3:])
            break
    print('prefix exact?',ok,'remaining inv total',sum(inv.values()))
