import json
import re
from collections import defaultdict, deque
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, Iterable, List, Tuple

import pandas as pd


ROOT = Path("/app")
RAW_ORDERS = ROOT / "raw_orders"
RAW_SUPPLIER = ROOT / "raw_supplier_receipts"
RAW_WHOLESALER = ROOT / "raw_wholesaler_receipts"
RAW_STORE = ROOT / "raw_wholesaler_store_receipts"
SALES_LOG = ROOT / "sales_log.csv"


PRODUCTS = [f"P_{i}" for i in range(1, 31)]
STORES = [f"S_{i}" for i in range(1, 11)]
PRODUCERS = [f"PR_{i}" for i in range(1, 61)]


def parse_supplier_doc(path: Path) -> List[Tuple[str, int]]:
    text = path.read_text().strip()
    if path.suffix == ".json":
        data = json.loads(text)
        return [(item["prod_id"], int(item["delivered_qty"])) for item in data["items"]]
    if path.suffix == ".csv":
        df = pd.read_csv(path, sep=";")
        return list(df[["PRODUCT", "DELIVERED_QTY"]].itertuples(index=False, name=None))
    if "key-value" in path.name:
        items = []
        for line in text.splitlines():
            match = re.search(r"PRODUCT: (P_\d+) \| DELIVERED_QTY: (\d+)", line)
            if match:
                items.append((match.group(1), int(match.group(2))))
        return items
    items = []
    for line in text.splitlines():
        match = re.search(r"delivered (\d+) units of product (P_\d+)", line, re.I)
        if match:
            items.append((match.group(2), int(match.group(1))))
    return items


def parse_order_doc(path: Path) -> List[Tuple[str, int]]:
    text = path.read_text().strip()
    if path.suffix == ".json":
        data = json.loads(text)
        return [(item["prod_id"], int(item["qty"])) for item in data["items"]]
    if path.suffix == ".csv":
        df = pd.read_csv(path, sep=";")
        return list(df[["PRODUCT", "QUANTITY"]].itertuples(index=False, name=None))
    if "key-value" in path.name:
        items = []
        for line in text.splitlines():
            match = re.search(r"ORDER_PRODUCT: (P_\d+) \| ORDER_QTY: (\d+)", line)
            if match:
                items.append((match.group(1), int(match.group(2))))
        return items
    items = []
    for line in text.splitlines():
        match = re.search(r"deliver (\d+) units of product (P_\d+)", line, re.I)
        if match:
            items.append((match.group(2), int(match.group(1))))
    return items


def parse_store_receipt(path: Path) -> Tuple[int, str, int]:
    text = path.read_text()
    day = int(re.search(r"DAY: (\d+)", text).group(1))
    store = re.search(r"STORE_ID: (S_\d+)", text).group(1)
    seq = int(re.search(r"DAILY_SEQUENCE_NO: (\d+)", text).group(1))
    total = int(re.search(r"TOTAL_DELIVERED_UNITS: (\d+)", text).group(1))
    return day, store, seq, total


def parse_wholesaler_receipt(path: Path) -> Tuple[int, str, int]:
    text = path.read_text()
    day = int(re.search(r"DAY: (\d+)", text).group(1))
    producer = re.search(r"SUPPLIER_ID: (PR_\d+)", text).group(1)
    seq = int(re.search(r"DAILY_SEQUENCE_NO: (\d+)", text).group(1))
    return day, producer, seq


def load_supply_frames():
    supplier_seq = {}
    for path in sorted(RAW_WHOLESALER.glob("*.txt")):
        day, producer, seq = parse_wholesaler_receipt(path)
        supplier_seq[(day, producer)] = seq

    supplier_rows = []
    for path in sorted(RAW_SUPPLIER.iterdir()):
        match = re.search(r"day_(\d+)_([A-Z]+_\d+)_", path.name)
        day = int(match.group(1))
        producer = match.group(2)
        seq = supplier_seq[(day, producer)]
        for product, qty in parse_supplier_doc(path):
            supplier_rows.append(
                {
                    "day": day,
                    "producer": producer,
                    "product": product,
                    "qty": int(qty),
                    "supplier_seq": seq,
                }
            )
    supplier_df = pd.DataFrame(supplier_rows).sort_values(
        ["day", "product", "supplier_seq", "producer"]
    )

    order_rows = []
    for path in sorted(RAW_ORDERS.iterdir()):
        match = re.search(r"day_(\d+)_(S_\d+)_", path.name)
        day = int(match.group(1))
        store = match.group(2)
        for product, qty in parse_order_doc(path):
            order_rows.append({"day": day, "store": store, "product": product, "qty": int(qty)})
    orders_df = pd.DataFrame(order_rows).sort_values(["day", "store", "product"])

    store_receipt_rows = []
    for path in sorted(RAW_STORE.glob("*.txt")):
        day, store, seq, total = parse_store_receipt(path)
        store_receipt_rows.append(
            {"day": day, "store": store, "store_seq": seq, "delivered_total": total}
        )
    store_receipts_df = pd.DataFrame(store_receipt_rows).sort_values(["day", "store_seq", "store"])

    return supplier_df, orders_df, store_receipts_df


def reconstruct_store_allocations(supplier_df: pd.DataFrame, orders_df: pd.DataFrame, store_receipts_df: pd.DataFrame):
    order_map = {
        (row.day, row.store, row.product): int(row.qty)
        for row in orders_df.itertuples(index=False)
    }
    day_store_seq = {
        (row.day, row.store): int(row.store_seq)
        for row in store_receipts_df.itertuples(index=False)
    }

    delivered_rows = []
    batch_rows = []
    for day in range(1, 366):
        stores = sorted(
            store_receipts_df.loc[store_receipts_df["day"] == day, ["store", "store_seq"]].itertuples(index=False),
            key=lambda x: x.store_seq,
        )
        daily_supply = supplier_df[supplier_df["day"] == day]
        for product in PRODUCTS:
            queue = deque()
            total_supply = 0
            sub = daily_supply[daily_supply["product"] == product]
            for row in sub.itertuples(index=False):
                queue.append([row.producer, int(row.qty), int(row.supplier_seq)])
                total_supply += int(row.qty)
            remaining = total_supply
            for store_row in stores:
                store = store_row.store
                ordered = int(order_map.get((day, store, product), 0))
                delivered = min(ordered, remaining)
                delivered_rows.append(
                    {
                        "day": day,
                        "store": store,
                        "product": product,
                        "order_qty": ordered,
                        "delivered_qty": delivered,
                        "store_seq": int(store_row.store_seq),
                    }
                )
                need = delivered
                while need > 0:
                    producer, avail, supplier_seq = queue[0]
                    take = min(need, avail)
                    batch_rows.append(
                        {
                            "day": day,
                            "store": store,
                            "product": product,
                            "producer": producer,
                            "supplier_day": day,
                            "supplier_seq": supplier_seq,
                            "qty": take,
                            "store_seq": int(store_row.store_seq),
                        }
                    )
                    need -= take
                    avail -= take
                    remaining -= take
                    if avail == 0:
                        queue.popleft()
                    else:
                        queue[0][1] = avail
                if need != 0:
                    raise RuntimeError(f"allocation failed for day={day} store={store} product={product}")
    delivered_df = pd.DataFrame(delivered_rows)
    batch_df = pd.DataFrame(batch_rows)
    return delivered_df, batch_df


def aggregate_sales():
    df = pd.read_csv(SALES_LOG)
    agg = (
        df.groupby(["Day", "Store_ID", "Product_ID"], as_index=False)[
            ["Reported_Demand", "Sold_Quantity", "Lost_Sales"]
        ]
        .sum()
        .rename(
            columns={
                "Day": "day",
                "Store_ID": "store",
                "Product_ID": "product",
                "Reported_Demand": "reported_demand",
                "Sold_Quantity": "sold_qty",
                "Lost_Sales": "lost_sales",
            }
        )
    )
    return df, agg


def reconstruct_store_sales(batch_df: pd.DataFrame, sales_agg: pd.DataFrame):
    intake_map: Dict[Tuple[str, str], Dict[int, List[Tuple[str, int, int, int]]]] = defaultdict(lambda: defaultdict(list))
    for row in batch_df.itertuples(index=False):
        intake_map[(row.store, row.product)][row.day].append(
            [row.producer, int(row.qty), int(row.supplier_day), int(row.supplier_seq)]
        )

    sales_map = {
        (row.day, row.store, row.product): int(row.sold_qty)
        for row in sales_agg.itertuples(index=False)
    }

    sold_rows = []
    for store in STORES:
        for product in PRODUCTS:
            queue = deque()
            for day in range(1, 366):
                for batch in intake_map[(store, product)].get(day, []):
                    queue.append(batch.copy())
                need = sales_map.get((day, store, product), 0)
                while need > 0:
                    if not queue:
                        raise RuntimeError(f"inventory underflow store={store} product={product} day={day}")
                    producer, avail, supplier_day, supplier_seq = queue[0]
                    take = min(need, avail)
                    sold_rows.append(
                        {
                            "day": day,
                            "store": store,
                            "product": product,
                            "producer": producer,
                            "qty": take,
                            "supplier_day": supplier_day,
                            "supplier_seq": supplier_seq,
                        }
                    )
                    need -= take
                    avail -= take
                    if avail == 0:
                        queue.popleft()
                    else:
                        queue[0][1] = avail
                if need != 0:
                    raise RuntimeError(f"sale allocation failed store={store} product={product} day={day}")
    sold_df = pd.DataFrame(sold_rows)
    return sold_df


def main():
    supplier_df, orders_df, store_receipts_df = load_supply_frames()
    delivered_df, batch_df = reconstruct_store_allocations(supplier_df, orders_df, store_receipts_df)
    raw_sales_df, sales_agg = aggregate_sales()
    sold_df = reconstruct_store_sales(batch_df, sales_agg)
    print("supplier rows", len(supplier_df))
    print("order rows", len(orders_df))
    print("delivery rows", len(delivered_df))
    print("batch rows", len(batch_df))
    print("sales rows", len(raw_sales_df))
    print("sold rows", len(sold_df))


if __name__ == "__main__":
    main()

